parameters.jsonBody:
={
  "contents": [
    {
      "role": "user",
      "parts": [
        {
          "text": "You are a sentiment and urgency analysis engine for an e-commerce platform. Analyze the customer review below and return ONLY a valid JSON object — no markdown, no explanation, no extra text.

Return exactly these fields:
{
  "sentiment": "positive" | "neutral" | "negative",
  "score": <number from -1.0 to 1.0>,
  "label": "Very Positive" | "Positive" | "Neutral" | "Negative" | "Very Negative",
  "urgency": "low" | "medium" | "high",
  "urgency_reason": "<one sentence explaining urgency level>"
}

Urgency guidelines:
- high: safety concern, defective product, data breach, severe health issue, or very angry customer threatening chargeback/legal action
- medium: item not as described, significant delay, missing parts, customer asking for immediate resolution
- low: minor complaint, general feedback, positive or neutral review, cosmetic issue

Consider BOTH the star rating AND the text.

Review ID: {{ $json.id }}
Product ID: {{ $json.product_id }}
Star Rating: {{ $json.rating }}/5
Title: {{ $json.title || 'No title' }}
Body: {{ $json.body }}"
        }
      ]
    }
  ],
  "generationConfig": {
    "temperature": 0.1,
    "maxOutputTokens": 200,
    "responseMimeType": "application/json"
  }
}

parameters.jsCode:
const review = $('Split Into Items').item.json;

// Extract Gemini response text
const candidates = $json.candidates || [];
const rawText = candidates[0]?.content?.parts?.[0]?.text || '{}';

let parsed;
try {
  const cleaned = rawText.replace(/```json|```/gi, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  // Fallback: derive from rating alone when parse fails
  const rating = review.rating || 3;
  const isNeg  = rating <= 2;
  const isPos  = rating >= 4;
  parsed = {
    sentiment:      isNeg ? 'negative' : isPos ? 'positive' : 'neutral',
    score:          parseFloat(((rating - 3) / 2).toFixed(3)),
    label:          isNeg ? 'Negative' : isPos ? 'Positive' : 'Neutral',
    urgency:        isNeg ? 'medium' : 'low',
    urgency_reason: 'Fallback heuristic — Gemini parse failed; derived from star rating.'
  };
}

// Validate enum values
const validSentiments = ['positive', 'neutral', 'negative'];
const validUrgencies  = ['low', 'medium', 'high'];

const sentiment = validSentiments.includes(parsed.sentiment) ? parsed.sentiment : 'neutral';
const urgency   = validUrgencies.includes(parsed.urgency)    ? parsed.urgency   : 'low';

return {
  review_id:       review.id,
  product_id:      review.product_id,
  rating:          review.rating,
  sentiment,
  sentiment_score: parseFloat((parsed.score || 0).toFixed(3)),
  sentiment_label: parsed.label         || 'Neutral',
  urgency,
  urgency_reason:  parsed.urgency_reason || 'No reason provided.',
  original_body:   review.body,
  original_title:  review.title || ''
};

// Aggregate batch results for logging
const allItems = $input.all();

const summary = {
  processed:       allItems.length,
  // Sentiment breakdown
  positive:        allItems.filter(i => i.json.sentiment === 'positive').length,
  neutral:         allItems.filter(i => i.json.sentiment === 'neutral').length,
  negative:        allItems.filter(i => i.json.sentiment === 'negative').length,
  // Urgency breakdown
  urgency_high:    allItems.filter(i => i.json.urgency === 'high').length,
  urgency_medium:  allItems.filter(i => i.json.urgency === 'medium').length,
  urgency_low:     allItems.filter(i => i.json.urgency === 'low').length,
  // Alerts fired (medium + high)
  alerts_sent:     allItems.filter(i => i.json.urgency !== 'low').length,
  timestamp:       new Date().toISOString(),
  model:           'gemini-2.0-flash'
};

console.log('Sentiment + Urgency batch summary:', JSON.stringify(summary, null, 2));
return summary;
